// src/App.js
import React from 'react';
import DashboardPage from './pages/DashboardPage';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import './styles/App.css';

// Protected Route component - FIXED: useAuth is called at the top level
const ProtectedRoute = ({ children }) => {
    const { user, loading } = useAuth(); // Called unconditionally at the top
    
    if (loading) {
        return <div className="loading">Loading...</div>;
    }
    
    return user ? children : <Navigate to="/login" />;
};

// Dashboard placeholder component
const DashboardPlaceholder = () => (
    <div style={{ textAlign: 'center', padding: '2rem' }}>
        <h2>Dashboard</h2>
        <p>Coming soon! This will display your health records.</p>
    </div>
);

function AppContent() {
    return (
        <div className="app">
            <header className="app-header">
                <h1>🏥 E-Health System</h1>
            </header>
            <main className="app-main">
                <Routes>
                    <Route path="/" element={<HomePage />} />
                    <Route path="/login" element={<LoginPage />} />
                    <Route path="/register" element={<RegisterPage />} />
                    <Route path="/dashboard" element={
                        <ProtectedRoute>
                            <DashboardPlaceholder />
                        </ProtectedRoute>
                    } />
                </Routes>
            </main>
        </div>
    );
}

function App() {
    return (
        <Router>
            <AuthProvider>
                <AppContent />
            </AuthProvider>
        </Router>
    );
}

export default App;
